import { hasInjectionContext, inject } from "vue";
import {
  useHead as headCore,
  useHeadSafe as headSafe,
  headSymbol,
  useSeoMeta as seoMeta,
  useServerHead as serverHead,
  useServerHeadSafe as serverHeadSafe,
  useServerSeoMeta as serverSeoMeta
} from "@unhead/vue";
import { tryUseNuxtApp } from "#app/nuxt";
export function injectHead(nuxtApp) {
  const nuxt = nuxtApp || tryUseNuxtApp();
  return nuxt?.ssrContext?.head || nuxt?.runWithContext(() => {
    if (hasInjectionContext()) {
      return inject(headSymbol);
    }
  });
}
export function useHead(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return headCore(input, { head, ...options });
  }
}
export function useHeadSafe(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return headSafe(input, { head, ...options });
  }
}
export function useSeoMeta(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return seoMeta(input, { head, ...options });
  }
}
export function useServerHead(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return serverHead(input, { head, ...options });
  }
}
export function useServerHeadSafe(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return serverHeadSafe(input, { head, ...options });
  }
}
export function useServerSeoMeta(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return serverSeoMeta(input, { head, ...options });
  }
}
import {
  findLocale,
  footerColumns,
  footerContact,
  footerLegalLinks,
  locales,
  localize,
  navigation,
  resolvePage,
  type LocaleCode,
  type LocalizedText
} from '~/data/site'

const paramValue = (value: string | string[] | undefined) => (Array.isArray(value) ? value[0] : value)

export const currentLocaleInfo = () => {
  const route = useRoute()

  return computed(() => findLocale(paramValue(route.params.locale)) ?? locales[0])
}

export const useSiteContent = () => {
  const route = useRoute()
  const locale = currentLocaleInfo()

  const currentSlug = computed(() => paramValue(route.params.slug))

  const buildPath = (slug?: string, localeCode: LocaleCode = locale.value.code) => {
    if (!slug || slug === localeCode) {
      return `/${localeCode}`
    }

    if (slug.startsWith('/')) {
      return slug
    }

    if (slug.startsWith(`${localeCode}/`)) {
      return `/${slug}`
    }

    return `/${localeCode}/${slug}`
  }

  const switchLocalePath = (localeCode: LocaleCode) => buildPath(currentSlug.value, localeCode)

  const textFor = (text: LocalizedText) => localize(text, locale.value.code)

  return {
    locale,
    currentSlug,
    locales,
    navigation,
    footerColumns,
    footerLegalLinks,
    footerContact,
    buildPath,
    switchLocalePath,
    textFor,
    resolveCurrentPage: () => resolvePage(currentSlug.value)
  }
}
